#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int st[MAXN],n,m,dis[MAXN],s;
vector<PII> g[MAXN];
void dijkstra(int s)
{
	cli(dis);
	cl(st);
	priority_queue<PII,vector<PII>,greater<>> q;
	dis[s]=0;
	q.push(mk(0,s));
	wh(q.size())
	{
		PII f=q.top();
		q.pop();
		int b=f.snd;
		if(st[b])continue;
        st[b]=1;
		FOI(s,g[b])
		{
			if(dis[s.fst]>dis[b]+s.snd)
			{
				dis[s.fst]=dis[b]+s.snd;
				q.push(mk(dis[s.fst],s.fst));
			}
		}
	}
} 
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cin>>n>>m>>s;
	FOR(i,1,m)
	{
		int u,v,w;
		cin>>u>>v>>w;
		g[u].pb(mk(v,w));
	}
	dijkstra(s);
	FOR(i,1,n)
	{
		cout<<dis[i]<<' '; 
	}
    return false;
}
